import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.util.ArrayList;
import java.util.List;
import org.apache.commons.logging.Log;
import org.apache.commons.logging.LogFactory;
import sailpoint.object.Application;
import sailpoint.object.AttributeDefinition;
import sailpoint.object.Identity;
import sailpoint.object.Link;
import sailpoint.object.ProvisioningPlan.AccountRequest;
import sailpoint.object.ProvisioningPlan.AccountRequest.Operation;
import sailpoint.object.ProvisioningPlan.AttributeRequest;
import sailpoint.object.ProvisioningPlan.Operation;
import sailpoint.object.ProvisioningResult;
import sailpoint.object.Schema;
import sailpoint.tools.Util;



Log prlogger = LogFactory.getLog("rule.sp.JDBCRuleLibrary");

/* Internal method for grabbing an Attribute Request Value. */
public Object getAttributeRequestValue(AccountRequest acctReq, String attribute) {
  Object attrValue=null;
  if (prlogger.isTraceEnabled()) {
    prlogger.trace("JDBCGRL-001: Attribute Name inside getAttributeRequestValue method----"+attribute);
  }
  if (null!=acctReq) {
    AttributeRequest attrReq = acctReq.getAttributeRequest(attribute);
    if (null!=attrReq) {
      attrValue = attrReq.getValue();
      if (attrValue instanceof List) {
        attrValue =(List) Util.filterNulls(attrValue);
        if (prlogger.isTraceEnabled()) {
          prlogger.trace("JDBCGRL-002: Attribute list value:" + attrValue);
        }
      }
    }
  }
  if (prlogger.isTraceEnabled()) {
    prlogger.trace("JDBCGRL-003: getAttributeRequestValue mehthod Attribute val----"+attrValue);
  }
  return attrValue;
}

public Object getAttributeRequestValueSingleRow(AccountRequest acctReq, String attribute) {
  Object attrValue=null;
  if (prlogger.isTraceEnabled()) {
    prlogger.trace("JDBCGRL-004: Attribute Name inside getAttributeRequestValue method----"+attribute);
  }
  AttributeRequest attrReq = acctReq.getAttributeRequest(attribute);
  if (null!=attrReq) {
    attrValue = attrReq.getValue();
    if (attrValue instanceof List) {
      attrValue =Util.listToCsv(attrValue);
      if (prlogger.isTraceEnabled()) {
        prlogger.trace("JDBCGRL-005: Attribute list value:" + attrValue);
      }
    }
  }
  if (prlogger.isTraceEnabled()) {
    prlogger.trace("JDBCGRL-006: getAttributeRequestValue mehthod Attribute val----"+attrValue);
  }
  return attrValue;
}

public ArrayList checkMultivaluedAttribute(List attributeRequests,ResultSetMetaData rsmd,Application application,String entitlementAttr)
{

  List multiattrList=new ArrayList();
  Schema schema=application.getSchema("account");
  /*Identifying a Multi-valued attribute*/
  for(int i=1;i<=rsmd.getColumnCount();i++)
  {
    for (AttributeRequest attributeRequest : attributeRequests) 
    {
      String attributeName = attributeRequest.getName();
      Object attributeObj=attributeRequest.getValue();
      if (rsmd.getColumnName(i).equals(attributeName)) 
      {
        if(schema.getAttributeDefinition(attributeName)!=null && schema.isMultiValued(attributeName) && !attributeName.equals(entitlementAttr)) 
        {
          multiattrList.add(attributeName);
          break;
        }
      }
    }
  }
  if (prlogger.isTraceEnabled()) {
    prlogger.trace("JDBCGRL-007: Multi Attribute name----"+multiattrList);
  } 

  return multiattrList;
}

public void insertEntitlementsInRows(List AttrAddListValues,List attributeList,String nativeIdentity,
                                     String entitlementAttr,AccountRequest acctReq,PreparedStatement prepareStatement,Connection connection,String tableName,String keyAttributeName)
{
  String checkEntsql="select * from "+tableName+" where "+entitlementAttr+"=? and "+keyAttributeName+"=?";
  PreparedStatement checkEntStatement=connection.prepareStatement(checkEntsql);
  if (prlogger.isTraceEnabled()) {
    prlogger.trace("JDBCGRL-008: Query to check existing entitlements in table---"+checkEntsql);
  }

  for(AttributeRequest addValuesattr:AttrAddListValues)
  {
    Object attrObj=addValuesattr.getValue(); //Entitlement AttributeRequest Value
    if(attrObj instanceof List)
    {
      for(String entVal:attrObj)
      {
        checkEntStatement.setString(1,entVal);		
        checkEntStatement.setString(2,nativeIdentity);
        ResultSet rs=checkEntStatement.executeQuery();

        if(!rs.next()) //Check for existing Entitlement value in table
        {		  
          prepareStatement.setString(1, nativeIdentity);
          for (int attributeIndx=1; attributeIndx<attributeList.size(); attributeIndx++) {
            if(attributeList.get(attributeIndx).equals(entitlementAttr))
            {
              prepareStatement.setString(attributeIndx+1,entVal);
            }
            else
            {
              prepareStatement.setString(attributeIndx+1, getAttributeRequestValue(acctReq, attributeList.get(attributeIndx)));
            }
          }
          if (prlogger.isTraceEnabled()) {
            prlogger.trace("JDBCGRL-009: Entitlement inserted----"+entVal);
          }
          prepareStatement.addBatch();
        }
      }
    }
    else
    {	
      checkEntStatement.setString(1,attrObj);
      checkEntStatement.setString(2,nativeIdentity);
      ResultSet rs=checkEntStatement.executeQuery();

      if(!rs.next()) //Check for existing Entitlement value in table
      {		  
        prepareStatement.setString(1, nativeIdentity);
        for (int attributeIndx=1; attributeIndx<attributeList.size(); attributeIndx++) {
          if(attributeList.get(attributeIndx).equals(entitlementAttr))
          {
            prepareStatement.setString(attributeIndx+1,attrObj);
          }
          else
          {
            prepareStatement.setString(attributeIndx+1, getAttributeRequestValue(acctReq, attributeList.get(attributeIndx)));
          }
        }
        if (prlogger.isTraceEnabled()) {
          prlogger.trace("JDBCGRL-010: Entitlement inserted----"+attrObj);
        }
        prepareStatement.addBatch();
      }
    }
  }
  prepareStatement.executeBatch();
}


public Boolean[] insertOrDeleteRecordFlag(ResultSetMetaData rsmd,String entitlementAttr,List AttrAddListValues,List AttrRemoveListValues,Boolean isInsertRow,Boolean isDeleteRow)
{
  Boolean[] result=new Boolean[2]; 
  for(int i=1;i<=rsmd.getColumnCount();i++)
  {
    if(rsmd.getColumnName(i).equals(entitlementAttr))
    {
      if(AttrAddListValues.size()>0 && AttrRemoveListValues.size()>0)
      {
        isInsertRow=true;
        isDeleteRow=true;
      }
      else if(AttrAddListValues.size()>0 && AttrRemoveListValues.size()==0)
      {
        isInsertRow=true;
      }
      else if(AttrAddListValues.size()==0 && AttrRemoveListValues.size()>0)
      {
        isDeleteRow=true;  
      }
      break;					  
    }					  		  
  }
  result[0]=isInsertRow;
  result[1]=isDeleteRow;

  return result;
}

public void insertMultivaluesintoRows(List multiattrList,AccountRequest acctReq,String tableName,String keyAttributeName,String nativeIdentity,PreparedStatement prepareStatement,List attributeList)
{
  //Size of a Multi-valued attribute value. This size should be same for all the multivalued attributes
  int commonSize=0;
  Object multiAttrValue=acctReq.getAttributeRequest(multiattrList.get(0)).getValue();
  if(multiAttrValue instanceof List)
  {
    commonSize=multiAttrValue.size();
  }
  else
  {
    commonSize=1;
  }
  if (prlogger.isTraceEnabled()) {
    prlogger.trace("JDBCGRL-011: Size of multivalued attribute---"+commonSize);
  }
  //Check to see any existing rows
  String checksql="select * from "+tableName+" where "+keyAttributeName+"=?";
  PreparedStatement checkStatement=connection.prepareStatement(checksql);
  if (prlogger.isTraceEnabled()) {
    prlogger.trace("JDBCGRL-012: Query to check existing multivalued attribute rows if any---"+checksql);
  }
  checkStatement.setString(1, nativeIdentity);
  ResultSet rs=checkStatement.executeQuery();

  if(rs.next())
  {
    //Deleting Existing rows from table
    String deletesql="delete from "+tableName+" where "+keyAttributeName+"=?";
    PreparedStatement deleteStatement=connection.prepareStatement(deletesql);
    if (prlogger.isTraceEnabled()) {
      prlogger.trace("JDBCGRL-013: Query to delete existing multivalued attribute rows: " + deletesql);
    }
    deleteStatement.setString(1, nativeIdentity); /* ProvisioningPlan nativeIdentity */
    deleteStatement.executeUpdate();
  }

  //Inserting new list of values in table
  if(commonSize>0)
  {
    for(int i=0;i<commonSize;i++)
    {
      prepareStatement.setString(1, nativeIdentity);
      /* Iterate throught attributes list to dynamically assign the values */
      for (int attributeIndx=1; attributeIndx<attributeList.size(); attributeIndx++) 
      {
        Object attributeObj=getAttributeRequestValue(acctReq, attributeList.get(attributeIndx));

        if(attributeObj instanceof List)
        {   
          prepareStatement.setString(attributeIndx+1, attributeObj.get(i));
          if (prlogger.isTraceEnabled()) {
            prlogger.trace("JDBCGRL-014: Value inserted----"+attributeObj.get(i));
          }
        }
        else
        {
          prepareStatement.setString(attributeIndx+1, attributeObj);
        }
      }
      prepareStatement.addBatch();
    }
    prepareStatement.executeBatch();
  }	
}

public void deleteMultivaluedAttrEntries(List multiattrList,AccountRequest acctReq,String tableName,String keyAttributeName,String nativeIdentity,PreparedStatement prepareStatement,List attributeList)
{
  //Check to see any existing rows
  String checksql="select * from "+tableName+" where "+keyAttributeName+"=?";
  PreparedStatement checkStatement=connection.prepareStatement(checksql);
  if (prlogger.isTraceEnabled()) {
    prlogger.trace("JDBCGRL-015: Query to check existing multivalued attribute rows if any---"+checksql);
  }
  checkStatement.setString(1, nativeIdentity);
  ResultSet rs=checkStatement.executeQuery();

  if(rs.next())
  {
    //Deleting Existing rows from table
    String deletesql="delete from "+tableName+" where "+keyAttributeName+"=?";
    PreparedStatement deleteStatement=connection.prepareStatement(deletesql);
    if (prlogger.isTraceEnabled()) {
      prlogger.trace("JDBCGRL-016: Query to delete existing multivalued attribute rows: " + deletesql);
    }
    deleteStatement.setString(1, nativeIdentity); /* ProvisioningPlan nativeIdentity */
    deleteStatement.executeUpdate();
  }
}

