public void deleteRecords(PreparedStatement prepareStatement,List AttrRemoveListValues,String nativeIdentity)
{
  for(AttributeRequest removeattrs:AttrRemoveListValues)
  {
    Object attrObj=removeattrs.getValue();//Entitlement AttributeRequest Value
    if(attrObj instanceof List)
    {
      for(String entVal :attrObj)
      {
        prepareStatement.setString(1, entVal);
        prepareStatement.setString(2, nativeIdentity);
        if (prlogger.isTraceEnabled()) {
          prlogger.trace("JDBCGRL-019: Entitlement removed-----"+entVal);
        }
        prepareStatement.addBatch();
      }
    }
    else
    {
      prepareStatement.setString(1, attrObj);
      prepareStatement.setString(2, nativeIdentity);
      if (prlogger.isTraceEnabled()) {
        prlogger.trace("JDBCGRL-020: Entitlement removed-----"+attrObj);
      }
      prepareStatement.addBatch();
    }
  }
  prepareStatement.executeBatch();
}	

/* Internal method to set the Provisioning Result to Failed if any error is encountered. */
public ProvisioningResult setFailedStatus(ProvisioningResult result, String errorMessage) {
  prlogger.error("JDBCGRL-021: "+errorMessage);
  result.setStatus(ProvisioningResult.STATUS_FAILED);
  result.addError(errorMessage);
  return(result);
}
